        // Base case: anything raised to 1 is itself
        if (n === 1) return x;

        // If 'n' is even
        if (n % 2 === 0) {
            // Recursive call: x * x, n / 2
            return this.power(x * x, Math.floor(n / 2));
        }

        // If 'n' is odd
        // Recursive call: x * power(x, n - 1)
        return x * this.power(x, n - 1);
    }

